import (
	"errors"
	"strings"

	"gno.land/p/nt/avl/v0"
)

type (
	// BoardIterFn defines a function type to iterate boards.
	BoardIterFn func(*Board) bool

	// Storage defines an interface for boards storage.
	Storage interface {
		// Get retruns a boards that matches an ID.
		Get(ID) (_ *Board, found bool)

		// GetByName retruns a boards that matches a name.
		GetByName(name string) (_ *Board, found bool)

		// Remove removes a board from the storage.
		Remove(ID) (_ *Board, removed bool)

		// Add adds a board to the storage.
		Add(*Board) error

		// Size returns the number of boards in the storage.
		Size() int

		// Iterate iterates boards.
		// To reverse iterate boards use a negative count.
		// If the callback returns true, the iteration is stopped.
		Iterate(start, count int, fn BoardIterFn) bool
	}
)

// NewStorage creates a new boards storage.
func NewStorage() Storage {
	return &storage{
		byID:   avl.NewTree(),
		byName: avl.NewTree(),
	}
}

type storage struct {
	byID   *avl.Tree // string(Board.ID) -> *Board
	byName *avl.Tree // Board.Name -> Board.ID
}

// Get returns a board for a specific ID.
func (s storage) Get(boardID ID) (*Board, bool) {
	key := makeBoardKey(boardID)
	v, found := s.byID.Get(key)
	if !found {
		return nil, false
	}
	return v.(*Board), true
}

// Get returns a board for a specific name.
func (s storage) GetByName(name string) (*Board, bool) {
	key := makeBoardNameKey(name)
	v, found := s.byName.Get(key)
	if !found {
		return nil, false
	}
	return s.Get(v.(ID))
}

// Remove removes a board from the storage.
// It returns false when board is not found.
func (s *storage) Remove(boardID ID) (*Board, bool) {
	board, found := s.Get(boardID)
	if !found {
		return nil, false
	}

	// Remove indexes for current and previous board names
	names := append([]string{board.Name}, board.Aliases...)
	for _, name := range names {
		key := makeBoardNameKey(name)

		// Make sure that name is indexed to the board being removed
		v, found := s.byName.Get(key)
		if found && v.(ID) == boardID {
			s.byName.Remove(key)
		}
	}

	key := makeBoardKey(board.ID)
	_, removed := s.byID.Remove(key)
	return board, removed
}

// Add adds a board to the storage.
// If board already exists it updates storage by reindexing the board by ID and name.
// When board name changes it's indexed so it can be found with the new and previous names.
func (s *storage) Add(board *Board) error {
	if board == nil {
		return errors.New("adding nil boards to the storage is not allowed")
	}

	key := makeBoardKey(board.ID)
	s.byID.Set(key, board)

	// Index by name when the optional board name is not empty
	if key = makeBoardNameKey(board.Name); key != "" {
		s.byName.Set(key, board.ID)
	}
	return nil
}

// Size returns the number of boards in the storage.
func (s storage) Size() int {
	return s.byID.Size()
}

// Iterate iterates boards.
// To reverse iterate boards use a negative count.
// If the callback returns true, the iteration is stopped.
func (s storage) Iterate(start, count int, fn BoardIterFn) bool {
	if count < 0 {
		return s.byID.ReverseIterateByOffset(start, -count, func(_ string, v any) bool {
			return fn(v.(*Board))
		})
	}

	return s.byID.IterateByOffset(start, count, func(_ string, v any) bool {
		return fn(v.(*Board))
	})
}

func makeBoardKey(boardID ID) string {
	return boardID.Key()
}

func makeBoardNameKey(name string) string {
	name = strings.TrimSpace(name)
	return strings.ToLower(name)
}

package boards

import (
	"errors"
	"strings"
	"time"

	"gno.land/p/nt/ufmt/v0"
)

// NewThread creates a new board thread.
func NewThread(b *Board, creator address, title, body string) (*Post, error) {
	if b == nil {
		return nil, errors.New("thread requires a parent board")
	}

	if !creator.IsValid() {
		return nil, ufmt.Errorf("invalid thread creator address: %s", creator)
	}

	title = strings.TrimSpace(title)
	if title == "" {
		return nil, errors.New("thread title is required")
	}

	body = strings.TrimSpace(body)
	if body == "" {
		return nil, errors.New("thread body is required")
	}

	id := b.ThreadsSequence.Next()
	return &Post{
		ID:        id,
		ThreadID:  id,
		Board:     b,
		Title:     title,
		Body:      body,
		Replies:   NewPostStorage(),
		Reposts:   NewRepostStorage(),
		Flags:     NewFlagStorage(),
		Creator:   creator,
		CreatedAt: time.Now(),
	}, nil
}

// MustNewThread creates a new thread or panics on error.
func MustNewThread(b *Board, creator address, title, body string) *Post {
	t, err := NewThread(b, creator, title, body)
	if err != nil {
		panic(err)
	}
	return t
}

// NewRepost creates a new thread that is a repost of a thread from another board.
func NewRepost(thread *Post, dst *Board, creator address) (*Post, error) {
	if thread == nil {
		return nil, errors.New("thread to repost is required")
	}

	if thread.Board == nil {
		return nil, errors.New("original thread has no board assigned")
	}

	if dst == nil {
		return nil, errors.New("thread repost requires a destination board")
	}

	if IsRepost(thread) {
		return nil, errors.New("reposting a thread that is a repost is not allowed")
	}

	if !IsThread(thread) {
		return nil, errors.New("post must be a thread to be reposted to another board")
	}

	if !creator.IsValid() {
		return nil, ufmt.Errorf("invalid thread repost creator address: %s", creator)
	}

	id := dst.ThreadsSequence.Next()
	return &Post{
		ID:              id,
		ThreadID:        id,
		ParentID:        thread.ID,
		OriginalBoardID: thread.Board.ID,
		Board:           dst,
		Replies:         NewPostStorage(),
		Reposts:         NewRepostStorage(),
		Flags:           NewFlagStorage(),
		Creator:         creator,
		CreatedAt:       time.Now(),
	}, nil
}

// MustNewRepost creates a new thread that is a repost of a thread from another board or panics on error.
func MustNewRepost(thread *Post, dst *Board, creator address) *Post {
	r, err := NewRepost(thread, dst, creator)
	if err != nil {
		panic(err)
	}
	return r
}

// Package addrset provides a specialized set data structure for managing unique Gno addresses.
//
// It is built on top of an AVL tree for efficient operations and maintains addresses in sorted order.
// This package is particularly useful when you need to:
//   - Track a collection of unique addresses (e.g., for whitelists, participants, etc.)
//   - Efficiently check address membership
//   - Support pagination when displaying addresses
//
// Example usage:
//
//	import (
//	    "std"
//	    "gno.land/p/moul/addrset"
//	)
//
//	func MyHandler() {
//	    // Create a new address set
//	    var set addrset.Set
//
//	    // Add some addresses
//	    addr1 := address("g1jg8mtutu9khhfwc4nxmuhcpftf0pajdhfvsqf5")
//	    addr2 := address("g1sss5g0rkqr88k4u648yd5d3l9t4d8vvqwszqth")
//
//	    set.Add(addr1)  // returns true (newly added)
//	    set.Add(addr2)  // returns true (newly added)
//	    set.Add(addr1)  // returns false (already exists)
//
//	    // Check membership
//	    if set.Has(addr1) {
//	        // addr1 is in the set
//	    }
//
//	    // Get size
//	    size := set.Size()  // returns 2
//
//	    // Iterate with pagination (10 items per page, starting at offset 0)
//	    set.IterateByOffset(0, 10, func(addr address) bool {
//	        // Process addr
//	        return false  // continue iteration
//	    })
//
//	    // Remove an address
//	    set.Remove(addr1)  // returns true (was present)
//	    set.Remove(addr1)  // returns false (not present)
//	}
package addrset

import "gno.land/p/nt/avl/v0"

type Set struct {
	tree avl.Tree
}

// Add inserts an address into the set.
// Returns true if the address was newly added, false if it already existed.
func (s *Set) Add(addr address) bool {
	return !s.tree.Set(string(addr), nil)
}

// Remove deletes an address from the set.
// Returns true if the address was found and removed, false if it didn't exist.
func (s *Set) Remove(addr address) bool {
	_, removed := s.tree.Remove(string(addr))
	return removed
}

// Has checks if an address exists in the set.
func (s *Set) Has(addr address) bool {
	return s.tree.Has(string(addr))
}

// Size returns the number of addresses in the set.
func (s *Set) Size() int {
	return s.tree.Size()
}

// IterateByOffset walks through addresses starting at the given offset.
// The callback should return true to stop iteration.
func (s *Set) IterateByOffset(offset int, count int, cb func(addr address) bool) {
	s.tree.IterateByOffset(offset, count, func(key string, _ any) bool {
		return cb(address(key))
	})
}

// ReverseIterateByOffset walks through addresses in reverse order starting at the given offset.
// The callback should return true to stop iteration.
func (s *Set) ReverseIterateByOffset(offset int, count int, cb func(addr address) bool) {
	s.tree.ReverseIterateByOffset(offset, count, func(key string, _ any) bool {
		return cb(address(key))
	})
}

// Tree returns the underlying AVL tree for advanced usage.
func (s *Set) Tree() avl.ITree {
	return &s.tree
}

// Package rotree provides a read-only wrapper for avl.Tree with safe value transformation.
//
// It is useful when you want to expose a read-only view of a tree while ensuring that
// the sensitive data cannot be modified.
//
// Example:
//
//	// Define a user structure with sensitive data
//	type User struct {
//		Name     string
//		Balance  int
//		Internal string // sensitive field
//	}
//
//	// Create and populate the original tree
//	privateTree := avl.NewTree()
//	privateTree.Set("alice", &User{
//		Name:     "Alice",
//		Balance:  100,
//		Internal: "sensitive",
//	})
//
//	// Create a safe transformation function that copies the struct
//	// while excluding sensitive data
//	makeEntrySafeFn := func(v any) any {
//		u := v.(*User)
//		return &User{
//			Name:     u.Name,
//			Balance:  u.Balance,
//			Internal: "", // omit sensitive data
//		}
//	}
//
//	// Create a read-only view of the tree
//	PublicTree := rotree.Wrap(tree, makeEntrySafeFn)
//
//	// Safely access the data
//	value, _ := roTree.Get("alice")
//	user := value.(*User)
//	// user.Name == "Alice"
//	// user.Balance == 100
//	// user.Internal == "" (sensitive data is filtered)
package rotree

import (
	"gno.land/p/nt/avl/v0"
)

// Wrap creates a new ReadOnlyTree from an existing avl.Tree and a safety transformation function.
// If makeEntrySafeFn is nil, values will be returned as-is without transformation.
//
// makeEntrySafeFn is a function that transforms a tree entry into a safe version that can be exposed to external users.
// This function should be implemented based on the specific safety requirements of your use case:
//
//  1. No-op transformation: For primitive types (int, string, etc.) or already safe objects,
//     simply pass nil as the makeEntrySafeFn to return values as-is.
//
//  2. Defensive copying: For mutable types like slices or maps, you should create a deep copy
//     to prevent modification of the original data.
//     Example: func(v any) any { return append([]int{}, v.([]int)...) }
//
//  3. Read-only wrapper: Return a read-only version of the object that implements
//     a limited interface.
//     Example: func(v any) any { return NewReadOnlyObject(v) }
//
//  4. DAO transformation: Transform the object into a data access object that
//     controls how the underlying data can be accessed.
//     Example: func(v any) any { return NewDAO(v) }
//
// The function ensures that the returned object is safe to expose to untrusted code,
// preventing unauthorized modifications to the original data structure.
func Wrap(tree *avl.Tree, makeEntrySafeFn func(any) any) *ReadOnlyTree {
	return &ReadOnlyTree{
		tree:            tree,
		makeEntrySafeFn: makeEntrySafeFn,
	}
}

// ReadOnlyTree wraps an avl.Tree and provides read-only access.
type ReadOnlyTree struct {
	tree            *avl.Tree
	makeEntrySafeFn func(any) any
}

// IReadOnlyTree defines the read-only operations available on a tree.
type IReadOnlyTree interface {
	Size() int
	Has(key string) bool
	Get(key string) (any, bool)
	GetByIndex(index int) (string, any)
	Iterate(start, end string, cb avl.IterCbFn) bool
	ReverseIterate(start, end string, cb avl.IterCbFn) bool
	IterateByOffset(offset int, count int, cb avl.IterCbFn) bool
	ReverseIterateByOffset(offset int, count int, cb avl.IterCbFn) bool
}

// Verify that ReadOnlyTree implements both ITree and IReadOnlyTree
var (
	_ avl.ITree     = (*ReadOnlyTree)(nil)
	_ IReadOnlyTree = (*ReadOnlyTree)(nil)
)

// getSafeValue applies the makeEntrySafeFn if it exists, otherwise returns the original value
func (roTree *ReadOnlyTree) getSafeValue(value any) any {
	if roTree.makeEntrySafeFn == nil {
		return value
	}
	return roTree.makeEntrySafeFn(value)
}

// Size returns the number of key-value pairs in the tree.
func (roTree *ReadOnlyTree) Size() int {
	return roTree.tree.Size()
}

// Has checks whether a key exists in the tree.
func (roTree *ReadOnlyTree) Has(key string) bool {
	return roTree.tree.Has(key)
}

// Get retrieves the value associated with the given key, converted to a safe format.
func (roTree *ReadOnlyTree) Get(key string) (any, bool) {
	value, exists := roTree.tree.Get(key)
	if !exists {
		return nil, false
	}
	return roTree.getSafeValue(value), true
}

// GetByIndex retrieves the key-value pair at the specified index in the tree, with the value converted to a safe format.
func (roTree *ReadOnlyTree) GetByIndex(index int) (string, any) {
	key, value := roTree.tree.GetByIndex(index)
	return key, roTree.getSafeValue(value)
}

// Iterate performs an in-order traversal of the tree within the specified key range.
func (roTree *ReadOnlyTree) Iterate(start, end string, cb avl.IterCbFn) bool {
	return roTree.tree.Iterate(start, end, func(key string, value any) bool {
		return cb(key, roTree.getSafeValue(value))
	})
}

// ReverseIterate performs a reverse in-order traversal of the tree within the specified key range.
func (roTree *ReadOnlyTree) ReverseIterate(start, end string, cb avl.IterCbFn) bool {
	return roTree.tree.ReverseIterate(start, end, func(key string, value any) bool {
		return cb(key, roTree.getSafeValue(value))
	})
}

// IterateByOffset performs an in-order traversal of the tree starting from the specified offset.
func (roTree *ReadOnlyTree) IterateByOffset(offset int, count int, cb avl.IterCbFn) bool {
	return roTree.tree.IterateByOffset(offset, count, func(key string, value any) bool {
		return cb(key, roTree.getSafeValue(value))
	})
}

// ReverseIterateByOffset performs a reverse in-order traversal of the tree starting from the specified offset.
func (roTree *ReadOnlyTree) ReverseIterateByOffset(offset int, count int, cb avl.IterCbFn) bool {
	return roTree.tree.ReverseIterateByOffset(offset, count, func(key string, value any) bool {
		return cb(key, roTree.getSafeValue(value))
	})
}

// Set is not supported on ReadOnlyTree and will panic.
func (roTree *ReadOnlyTree) Set(key string, value any) bool {
	panic("Set operation not supported on ReadOnlyTree")
}

// Remove is not supported on ReadOnlyTree and will panic.
func (roTree *ReadOnlyTree) Remove(key string) (value any, removed bool) {
	panic("Remove operation not supported on ReadOnlyTree")
}

// RemoveByIndex is not supported on ReadOnlyTree and will panic.
func (roTree *ReadOnlyTree) RemoveByIndex(index int) (key string, value any) {
	panic("RemoveByIndex operation not supported on ReadOnlyTree")
}

// Package list implements a dynamic list data structure backed by an AVL tree.
// It provides O(log n) operations for most list operations while maintaining
// order stability.
//
// The list supports various operations including append, get, set, delete,
// range queries, and iteration. It can store values of any type.
//
// Example usage:
//
//	// Create a new list and add elements
//	var l list.List
//	l.Append(1, 2, 3)
//
//	// Get and set elements
//	value := l.Get(1)  // returns 2
//	l.Set(1, 42)      // updates index 1 to 42
//
//	// Delete elements
//	l.Delete(0)       // removes first element
//
//	// Iterate over elements
//	l.ForEach(func(index int, value any) bool {
//	    ufmt.Printf("index %d: %v\n", index, value)
//	    return false  // continue iteration
//	})
//	// Output:
//	// index 0: 42
//	// index 1: 3
//
//	// Create a list of specific size
//	l = list.Make(3, "default")  // creates [default, default, default]
//
//	// Create a list using a variable declaration
//	var l2 list.List
//	l2.Append(4, 5, 6)
//	println(l2.Len())  // Output: 3
package list

import (
	"gno.land/p/nt/avl/v0"
	"gno.land/p/nt/avl/v0/rotree"
	"gno.land/p/nt/seqid/v0"
)

// IList defines the interface for list operations
type IList interface {
	Len() int
	Append(values ...any)
	Get(index int) any
	Set(index int, value any) bool
	Delete(index int) (any, bool)
	Slice(startIndex, endIndex int) []any
	ForEach(fn func(index int, value any) bool)
	Clone() *List
	DeleteRange(startIndex, endIndex int) int
}

// Verify List implements IList interface
var _ IList = (*List)(nil)

// List represents an ordered sequence of items backed by an AVL tree
type List struct {
	tree  avl.Tree
	idGen seqid.ID
}

// Len returns the number of elements in the list.
//
// Example:
//
//	var l list.List
//	l.Append(1, 2, 3)
//	println(l.Len()) // Output: 3
func (l *List) Len() int {
	return l.tree.Size()
}

// Append adds one or more values to the end of the list.
//
// Example:
//
//	var l list.List
//	l.Append(1)        // adds single value
//	l.Append(2, 3, 4)  // adds multiple values
//	println(l.Len()) // Output: 4
func (l *List) Append(values ...any) {
	for _, v := range values {
		l.tree.Set(l.idGen.Next().String(), v)
	}
}

// Get returns the value at the specified index.
// Returns nil if index is out of bounds.
//
// Example:
//
//	var l list.List
//	l.Append(1, 2, 3)
//	println(l.Get(1))    // Output: 2
//	println(l.Get(-1))   // Output: nil
//	println(l.Get(999))  // Output: nil
func (l *List) Get(index int) any {
	if index < 0 || index >= l.tree.Size() {
		return nil
	}
	_, value := l.tree.GetByIndex(index)
	return value
}

// Set updates or appends a value at the specified index.
// Returns true if the operation was successful, false otherwise.
// For empty lists, only index 0 is valid (append case).
//
// Example:
//
//	var l list.List
//	l.Append(1, 2, 3)
//
//	l.Set(1, 42)      // updates existing index
//	println(l.Get(1)) // Output: 42
//
//	l.Set(3, 4)       // appends at end
//	println(l.Get(3)) // Output: 4
//
//	l.Set(-1, 5)      // invalid index
//	println(l.Len()) // Output: 4 (list unchanged)
func (l *List) Set(index int, value any) bool {
	size := l.tree.Size()

	// Handle empty list case - only allow index 0
	if size == 0 {
		if index == 0 {
			l.Append(value)
			return true
		}
		return false
	}

	if index < 0 || index > size {
		return false
	}

	// If setting at the end (append case)
	if index == size {
		l.Append(value)
		return true
	}

	// Get the key at the specified index
	key, _ := l.tree.GetByIndex(index)
	if key == "" {
		return false
	}

	// Update the value at the existing key
	l.tree.Set(key, value)
	return true
}

// Delete removes the element at the specified index.
// Returns the deleted value and true if successful, nil and false otherwise.
//
// Example:
//
//	var l list.List
//	l.Append(1, 2, 3)
//
//	val, ok := l.Delete(1)
//	println(val, ok)  // Output: 2 true
//	println(l.Len())  // Output: 2
//
//	val, ok = l.Delete(-1)
//	println(val, ok)  // Output: nil false
func (l *List) Delete(index int) (any, bool) {
	size := l.tree.Size()
	// Always return nil, false for empty list
	if size == 0 {
		return nil, false
	}

	if index < 0 || index >= size {
		return nil, false
	}

	key, value := l.tree.GetByIndex(index)
	if key == "" {
		return nil, false
	}

	l.tree.Remove(key)
	return value, true
}

// Slice returns a slice of values from startIndex (inclusive) to endIndex (exclusive).
// Returns nil if the range is invalid.
//
// Example:
//
//	var l list.List
//	l.Append(1, 2, 3, 4, 5)
//
//	println(l.Slice(1, 4))   // Output: [2 3 4]
//	println(l.Slice(-1, 2))  // Output: [1 2]
//	println(l.Slice(3, 999)) // Output: [4 5]
//	println(l.Slice(3, 2))   // Output: nil
func (l *List) Slice(startIndex, endIndex int) []any {
	size := l.tree.Size()

	// Normalize bounds
	if startIndex < 0 {
		startIndex = 0
	}
	if endIndex > size {
		endIndex = size
	}
	if startIndex >= endIndex {
		return nil
	}

	count := endIndex - startIndex
	result := make([]any, count)

	i := 0
	l.tree.IterateByOffset(startIndex, count, func(_ string, value any) bool {
		result[i] = value
		i++
		return false
	})
	return result
}

// ForEach iterates through all elements in the list.
func (l *List) ForEach(fn func(index int, value any) bool) {
	if l.tree.Size() == 0 {
		return
	}

	index := 0
	l.tree.IterateByOffset(0, l.tree.Size(), func(_ string, value any) bool {
		result := fn(index, value)
		index++
		return result
	})
}

// Clone creates a shallow copy of the list.
//
// Example:
//
//	var l list.List
//	l.Append(1, 2, 3)
//
//	clone := l.Clone()
//	clone.Set(0, 42)
//
//	println(l.Get(0))    // Output: 1
//	println(clone.Get(0)) // Output: 42
func (l *List) Clone() *List {
	newList := &List{
		tree:  avl.Tree{},
		idGen: l.idGen,
	}

	size := l.tree.Size()
	if size == 0 {
		return newList
	}

	l.tree.IterateByOffset(0, size, func(_ string, value any) bool {
		newList.Append(value)
		return false
	})

	return newList
}

// DeleteRange removes elements from startIndex (inclusive) to endIndex (exclusive).
// Returns the number of elements deleted.
//
// Example:
//
//	var l list.List
//	l.Append(1, 2, 3, 4, 5)
//
//	deleted := l.DeleteRange(1, 4)
//	println(deleted)     // Output: 3
//	println(l.Range(0, l.Len())) // Output: [1 5]
func (l *List) DeleteRange(startIndex, endIndex int) int {
	size := l.tree.Size()

	// Normalize bounds
	if startIndex < 0 {
		startIndex = 0
	}
	if endIndex > size {
		endIndex = size
	}
	if startIndex >= endIndex {
		return 0
	}

	// Collect keys to delete
	keysToDelete := make([]string, 0, endIndex-startIndex)
	l.tree.IterateByOffset(startIndex, endIndex-startIndex, func(key string, _ any) bool {
		keysToDelete = append(keysToDelete, key)
		return false
	})

	// Delete collected keys
	for _, key := range keysToDelete {
		l.tree.Remove(key)
	}

	return len(keysToDelete)
}

// Tree returns a read-only pointer to the underlying AVL tree.
//
// Example:
//
//	var l list.List
//	l.Append(1, 2, 3)
//
//	rotree := l.Tree()
//	rotree.ReverseIterateByOffset(0, rotree.Size(), func(key string, value any) bool {
//	  println(value) // Output: 3 2 1
//	  return false
//	})
func (l *List) Tree() *rotree.ReadOnlyTree {
	return rotree.Wrap(&l.tree, nil)
}

package commondao

import (
	"errors"

	"gno.land/p/nt/avl/v0/list"
	"gno.land/p/nt/seqid/v0"
)

// PathSeparator is the separator character used in DAO paths.
const PathSeparator = "/"

var (
	ErrExecutionNotAllowed  = errors.New("proposal must pass before execution")
	ErrInvalidVoteChoice    = errors.New("invalid vote choice")
	ErrNotMember            = errors.New("account is not a member of the DAO")
	ErrOverflow             = errors.New("next ID overflows uint64")
	ErrProposalNotFound     = errors.New("proposal not found")
	ErrVotingDeadlineNotMet = errors.New("voting deadline not met")
	ErrVotingDeadlinePassed = errors.New("voting deadline has passed")
	ErrWithdrawalNotAllowed = errors.New("withdrawal not allowed for proposals with votes")
)

// CommonDAO defines a DAO.
type CommonDAO struct {
	id                         uint64
	slug                       string
	name                       string
	description                string
	parent                     *CommonDAO
	children                   list.IList
	members                    MemberStorage
	genID                      seqid.ID
	activeProposals            ProposalStorage
	finishedProposals          ProposalStorage
	deleted                    bool // Soft delete
	disableVotingDeadlineCheck bool
}

// New creates a new common DAO.
func New(options ...Option) *CommonDAO {
	dao := &CommonDAO{
		children:          &list.List{},
		members:           NewMemberStorage(),
		activeProposals:   NewProposalStorage(),
		finishedProposals: NewProposalStorage(),
	}
	for _, apply := range options {
		apply(dao)
	}
	return dao
}

// ID returns DAO's unique identifier.
func (dao CommonDAO) ID() uint64 {
	return dao.id
}

// Slug returns DAO's URL slug.
func (dao CommonDAO) Slug() string {
	return dao.slug
}

// Name returns DAO's name.
func (dao CommonDAO) Name() string {
	return dao.name
}

// Description returns DAO's description.
func (dao CommonDAO) Description() string {
	return dao.description
}

// Path returns the full path to the DAO.
// Paths are normally used when working with hierarchical
// DAOs and is created by concatenating DAO slugs.
func (dao CommonDAO) Path() string {
	// NOTE: Path could be a value but there might be use cases where dynamic path is useful (?)
	parent := dao.Parent()
	if parent != nil {
		prefix := parent.Path()
		if prefix != "" {
			return prefix + PathSeparator + dao.slug
		}
	}
	return dao.slug
}

// Parent returns the parent DAO.
// Null can be returned when DAO has no parent assigned.
func (dao CommonDAO) Parent() *CommonDAO {
	return dao.parent
}

// Children returns a list with the direct DAO children.
// Each item in the list is a reference to a CommonDAO instance.
func (dao CommonDAO) Children() list.IList {
	return dao.children
}

// TopParent returns the topmost parent DAO.
// The top parent is the root of the DAO tree.
func (dao *CommonDAO) TopParent() *CommonDAO {
	parent := dao.Parent()
	if parent != nil {
		return parent.TopParent()
	}
	return dao
}

// Members returns the list of DAO members.
func (dao CommonDAO) Members() MemberStorage {
	return dao.members
}

// ActiveProposals returns active DAO proposals.
func (dao CommonDAO) ActiveProposals() ProposalStorage {
	return dao.activeProposals
}

// FinishedProposalsi returns finished DAO proposals.
func (dao CommonDAO) FinishedProposals() ProposalStorage {
	return dao.finishedProposals
}

// IsDeleted returns true when DAO has been soft deleted.
func (dao CommonDAO) IsDeleted() bool {
	return dao.deleted
}

// SetDeleted changes DAO's soft delete flag.
func (dao *CommonDAO) SetDeleted(deleted bool) {
	dao.deleted = deleted
}

// Propose creates a new DAO proposal.
func (dao *CommonDAO) Propose(creator address, d ProposalDefinition) (*Proposal, error) {
	id, ok := dao.genID.TryNext()
	if !ok {
		return nil, ErrOverflow
	}

	p, err := NewProposal(uint64(id), creator, d)
	if err != nil {
		return nil, err
	}

	dao.activeProposals.Add(p)
	return p, nil
}

// MustPropose creates a new DAO proposal or panics on error.
func (dao *CommonDAO) MustPropose(creator address, d ProposalDefinition) *Proposal {
	p, err := dao.Propose(creator, d)
	if err != nil {
		panic(err)
	}
	return p
}

// GetProposal returns a proposal or nil when proposal is not found.
func (dao CommonDAO) GetProposal(proposalID uint64) *Proposal {
	p := dao.activeProposals.Get(proposalID)
	if p != nil {
		return p
	}
	return dao.finishedProposals.Get(proposalID)
}

// Withdraw withdraws a proposal that has no votes.
// Only proposals without votes can be withdrawn, and once
// withdrawn they are considered finished.
func (dao *CommonDAO) Withdraw(proposalID uint64) error {
	p := dao.activeProposals.Get(proposalID)
	if p == nil {
		return ErrProposalNotFound
	}

	if p.VotingRecord().Size() > 0 {
		return ErrWithdrawalNotAllowed
	}

	p.status = StatusWithdrawn
	dao.activeProposals.Remove(p.id)
	dao.finishedProposals.Add(p)
	return nil
}

// Vote submits a new vote for a proposal.
//
// By default votes are only allowed to members of the DAO when the proposal is active,
// and within the voting period. No votes are allowed once the voting deadline passes.
// DAO deadline checks can optionally be disabled using the `DisableVotingDeadlineCheck` option.
func (dao *CommonDAO) Vote(member address, proposalID uint64, c VoteChoice, reason string) error {
	if !dao.Members().Has(member) {
		return ErrNotMember
	}

	p := dao.activeProposals.Get(proposalID)
	if p == nil {
		return ErrProposalNotFound
	}

	if !dao.disableVotingDeadlineCheck && p.HasVotingDeadlinePassed() {
		return ErrVotingDeadlinePassed
	}

	if !p.IsVoteChoiceValid(c) {
		return ErrInvalidVoteChoice
	}

	p.record.AddVote(Vote{
		Address: member,
		Choice:  c,
		Reason:  reason,
	})
	return nil
}

// Execute executes a proposal.
//
// By default active proposals can only be executed after their voting deadline passes.
// DAO deadline checks can optionally be disabled using the `DisableVotingDeadlineCheck` option.
func (dao *CommonDAO) Execute(proposalID uint64) error {
	p := dao.activeProposals.Get(proposalID)
	if p == nil {
		return ErrProposalNotFound
	}

	// Proposal must be active or have passed to be executed
	if p.status != StatusActive && p.status != StatusPassed {
		return ErrExecutionNotAllowed
	}

	// Execution must be done after voting deadline
	if !dao.disableVotingDeadlineCheck && !p.HasVotingDeadlinePassed() {
		return ErrVotingDeadlineNotMet
	}

	// IMPORTANT, from this point on, any error is going to result
	// in a proposal failure and execute will succeed.

	// Validate proposal before execution
	err := p.Validate()

	// Tally votes and update proposal status to "passed" or "rejected"
	if err == nil {
		err = p.Tally(dao.Members())
		if err == nil && p.Status() == StatusRejected {
			// Don't try to execute proposal if it's been rejected
			return nil
		}
	}

	// Execute proposal only if it's executable
	if err == nil {
		if e, ok := p.Definition().(Executable); ok {
			if fn := e.Executor(); fn != nil {
				err = fn(cross)
			}
		}
	}

	// Proposal fails if there is any error during validation and execution process
	if err != nil {
		p.status = StatusFailed
		p.statusReason = err.Error()
	} else {
		p.status = StatusExecuted
	}

	// Whichever the outcome of the validation, tallying
	// and execution consider the proposal finished.
	dao.activeProposals.Remove(p.id)
	dao.finishedProposals.Add(p)
	return nil
}

package commondao

// Option configures the CommonDAO.
type Option func(*CommonDAO)

// WithID assigns a unique identifier to the DAO.
func WithID(id uint64) Option {
	return func(dao *CommonDAO) {
		dao.id = id
	}
}

// WithName assigns a name to the DAO.
func WithName(name string) Option {
	return func(dao *CommonDAO) {
		dao.name = name
	}
}

// WithDescription assigns a description to the DAO.
func WithDescription(description string) Option {
	return func(dao *CommonDAO) {
		dao.description = description
	}
}

// WithSlug assigns a URL slug to the DAO.
func WithSlug(slug string) Option {
	return func(dao *CommonDAO) {
		dao.slug = slug
	}
}

// WithParent assigns a parent DAO.
func WithParent(p *CommonDAO) Option {
	return func(dao *CommonDAO) {
		dao.parent = p
	}
}

// WithChildren assigns one or more direct child SubDAOs to the DAO.
func WithChildren(children ...*CommonDAO) Option {
	return func(dao *CommonDAO) {
		for _, subDAO := range children {
			dao.children.Append(subDAO)
		}
	}
}

// WithMember assigns a member to the DAO.
func WithMember(addr address) Option {
	return func(dao *CommonDAO) {
		dao.members.Add(addr)
	}
}

// WithMemberStorage assigns a custom member storage to the DAO.
// An empty member storage is used by default if the specified storage is nil.
func WithMemberStorage(s MemberStorage) Option {
	return func(dao *CommonDAO) {
		if s == nil {
			s = NewMemberStorage()
		}
		dao.members = s
	}
}

// WithActiveProposalStorage assigns a custom storage for active proposals.
// A default empty proposal storage is used when the custopm storage is nil.
// Custom storage implementations can be used to store proposals in a different location.
func WithActiveProposalStorage(s ProposalStorage) Option {
	return func(dao *CommonDAO) {
		if s == nil {
			s = NewProposalStorage()
		}
		dao.activeProposals = s
	}
}

// WithFinishedProposalStorage assigns a custom storage for finished proposals.
// A default empty proposal storage is used when the custopm storage is nil.
// Custom storage implementations can be used to store proposals in a different location.
func WithFinishedProposalStorage(s ProposalStorage) Option {
	return func(dao *CommonDAO) {
		if s == nil {
			s = NewProposalStorage()
		}
		dao.finishedProposals = s
	}
}

// DisableVotingDeadlineCheck disables voting deadline check when voting or executing proposals.
// By default CommonDAO checks that the proposal voting deadline has not been met when a new vote
// is submitted, before registering the vote, and on proposal execution it also checks that voting
// deadline has been met before executing a proposal.
//
// Disabling these checks can be useful in different use cases, moving the responsibility to check
// the deadline to the commondao package caller. One example where this could be useful would be
// in case where 100% or a required number of members of a DAO vote on a proposal and reach consensus
// before the deadline is met, otherwise proposal would have to wait until deadline to be executed.
func DisableVotingDeadlineCheck() Option {
	return func(dao *CommonDAO) {
		dao.disableVotingDeadlineCheck = true
	}
}

