# CommonDAO Package Definition Extension

Definition package is an extension of `gno.land/p/nt/commondao/v0` that provides
an alternative approach to define custom proposal types.

## Definition

The `Definition` type is an implementation that allows creating custom proposal
definitions using callback functions and definition options.

CommonDAO package supports different proposal types through the
`ProposalDefinition` interface, so new proposal types require the definition
of a custom type that implements the interface. The `Definition` type is a
callback based alternative to the type based approach.

By default, new definitions have a voting period of 7 days, allowing _YES_,
_NO_ and _ABSTAIN_ votes, tallying those votes using an absolute majority of
more than 50% of member votes, considering that a proposal passes when the
majority of the votes are _YES_.

New definition can be created using any of the following functions:

```go
// New creates a new custom proposal definition or returns an error
func New(title, body string, options ...Option) (Definition, error)

// MustNew creates a new custom proposal definition or panics on error
func MustNew(title, body string, options ...Option) Definition
```

Default definition behavior can be configured by setting custom options that
configures the following proposal options:

- Custom vote choices
- Voting period
- Tally behavior
- Pre-execution and render validation
- Execution behavior

Example usage:

```go
import (
  "chain/runtime"
  "errors"
  "time"

  "gno.land/p/nt/commondao/v0"
  "gno.land/p/nt/commondao/v0/exts/definition"
)

var dao = commondao.New()

// CreateMemberProposal creates a new example proposal to add a DAO member.
func CreateMemberProposal(member address) uint64 {
  if !member.IsValid() {
    panic("invalid member address")
  }

  // Define a function to validate that member doesn't exist within the DAO
  validate := func() error {
    if dao.Members().Has(member) {
      return errors.New("member already exists within the DAO")
    }
    return nil
  }

  // Define a custom tally function that approves proposals without votes
  tally := func(commondao.VotingContext) (bool, error) {
    return true, nil
  }

  // Define an executor to add the new member to the DAO
  executor := func(realm) error {
    dao.Members().Add(member)
    return nil
  }

  // Create a custom proposal definition for an example proposal type
  def := definition.MustNew(
    "Example Proposal",
    "This is a simple proposal example",
    definition.WithVotingPeriod(time.Hour * 24 * 2), // 2 days
    definition.WithTally(tally),
    definition.WithValidation(validate),
    definition.WithExecutor(executor),
  )

  // Create a new proposal
  p := dao.MustPropose(runtime.PreviousRealm().Address(), def)
  return p.ID()
}
```

package definition

import (
	"errors"
	"strings"
	"time"

	"gno.land/p/nt/commondao/v0"
)

// DefaultVotingPeriod defines the default voting period for proposals.
const DefaultVotingPeriod = time.Hour * 24 * 7

var (
	ErrBodyIsRequired  = errors.New("proposal body is required")
	ErrTitleIsRequired = errors.New("proposal title is required")
)

var defaultVoteChoices = []commondao.VoteChoice{
	commondao.ChoiceYes,
	commondao.ChoiceNo,
	commondao.ChoiceAbstain,
}

// TallyFunc defines a function to handle proposal votes tallying.
type TallyFunc func(commondao.VotingContext) (passes bool, _ error)

// New creates a new proposal definition.
//
// By default, new definitions have a voting period of 7 days, allowing YES, NO and
// ABSTAIN votes, tallying those votes using an absolute majority of more than 50% of
// member votes, considering that a proposal passes when the majority of the votes are YES.
//
// Default definition behavior can be configured by setting custom options.
func New(title, body string, options ...Option) (Definition, error) {
	title = strings.TrimSpace(title)
	if title == "" {
		return Definition{}, ErrTitleIsRequired
	}

	body = strings.TrimSpace(body)
	if body == "" {
		return Definition{}, ErrBodyIsRequired
	}

	def := Definition{
		title:        title,
		body:         body,
		votingPeriod: DefaultVotingPeriod,
		voteChoices:  defaultVoteChoices,
		tallyCb:      TallyByAbsoluteMajority,
	}
	for _, apply := range options {
		apply(&def)
	}
	return def, nil
}

// MustNew creates a new proposal definition or panics on error.
func MustNew(title, body string, options ...Option) Definition {
	def, err := New(title, body, options...)
	if err != nil {
		panic(err)
	}
	return def
}

// Definition defines CommonDAO proposal types.
type Definition struct {
	title        string
	body         string
	votingPeriod time.Duration
	voteChoices  []commondao.VoteChoice
	tallyCb      TallyFunc
	validateCb   func() error
	executeCb    commondao.ExecFunc
}

// Title returns the proposal title.
func (d Definition) Title() string {
	return d.title
}

// Body returns proposal's body.
func (d Definition) Body() string {
	return d.body
}

// VotingPeriod returns the period where votes are allowed after proposal creation.
func (d Definition) VotingPeriod() time.Duration {
	return d.votingPeriod
}

// CustomVoteChoices returns a list of valid voting choices.
func (d Definition) CustomVoteChoices() []commondao.VoteChoice {
	return d.voteChoices
}

// Tally counts the number of votes and verifies if proposal passes.
func (d Definition) Tally(ctx commondao.VotingContext) (passes bool, _ error) {
	return d.tallyCb(ctx)
}

// Validate validates that the proposal is valid for the current state.
func (d Definition) Validate() error {
	if d.validateCb != nil {
		return d.validateCb()
	}
	return nil
}

// Executor returns a function to execute the proposal.
func (d Definition) Executor() commondao.ExecFunc {
	return d.executeCb
}

// TallyByAbsoluteMajority tallies votes by absolute majority.
// A quorum of 51% of member votes is required to tally votes.
// Tally considers that proposals passes when more than half of members votes YES.
func TallyByAbsoluteMajority(ctx commondao.VotingContext) (bool, error) {
	// Check if a quorum of 51% has been met
	if !commondao.IsQuorumReached(commondao.QuorumMoreThanHalf, ctx.VotingRecord, ctx.Members) {
		return false, commondao.ErrNoQuorum
	}

	// Tally votes by absolute majority, which requires 51% votes
	c, success := commondao.SelectChoiceByAbsoluteMajority(ctx.VotingRecord, ctx.Members.Size())
	if success {
		return c == commondao.ChoiceYes, nil
	}
	return false, nil
}

package definition

import (
	"strconv"
	"time"

	"gno.land/p/nt/commondao/v0"
)

// Option configures CommonDAO proposal definitions.
type Option func(*Definition)

// WithVoteChoices configures a proposal to use custom voting choices.
// It panics when there are less than two choices or when a voting choice is duplicated.
func WithVoteChoices(choices []commondao.VoteChoice) Option {
	count := len(choices)
	if count < 2 {
		panic("proposal requires at least two voting choices: got " + strconv.Itoa(count))
	}

	return func(d *Definition) {
		seen := make(map[commondao.VoteChoice]struct{}, count)
		d.voteChoices = make([]commondao.VoteChoice, count)
		for i, choice := range choices {
			if _, found := seen[choice]; found {
				panic("proposal voting choice is duplicated: " + string(choice))
			}

			seen[choice] = struct{}{}
			d.voteChoices[i] = choice
		}
	}
}

// WithVotingPeriod configures the voting period of a proposal.
// It panics when voting period is negative.
func WithVotingPeriod(period time.Duration) Option {
	if period < 0 {
		// Zero allows unit testing of proposals
		panic("voting period of proposal must be greater or equal to zero")
	}

	return func(d *Definition) {
		d.votingPeriod = period
	}
}

// WithTally configures a proposal definition to use a custom vote tallying.
// New definitions tally using simple majority (51%) by default.
// It panics when tally callback is nil.
func WithTally(cb TallyFunc) Option {
	if cb == nil {
		panic("proposal tally callback is nil")
	}

	return func(d *Definition) {
		d.tallyCb = cb
	}
}

// WithValidation configures a proposal definition to support proposal validation.
// Validation is done before execution and normally also during proposal rendering.
// It panics when validation callback is nil.
func WithValidation(cb func() error) Option {
	if cb == nil {
		panic("proposal validation callback is nil")
	}

	return func(d *Definition) {
		d.validateCb = cb
	}
}

// WithExecutor configures a proposal definition to support proposal execution.
// It panics when executor callback is nil.
func WithExecutor(cb commondao.ExecFunc) Option {
	if cb == nil {
		panic("proposal executor callback is nil")
	}

	return func(d *Definition) {
		d.executeCb = cb
	}
}

