//
// Package ownable provides an ownership pattern for Gno realms, allowing
// contracts to restrict access to privileged operations to a designated owner.
package ownable

package ownable

import "errors"

var (
	ErrUnauthorized   = errors.New("ownable: caller is not owner")
	ErrInvalidAddress = errors.New("ownable: new owner address is invalid")
)

package ownable

import (
	"chain"
	"chain/runtime"
)

const OwnershipTransferEvent = "OwnershipTransfer"

// Ownable is meant to be used as a top-level object to make your contract ownable OR
// being embedded in a Gno object to manage per-object ownership.
// Ownable is safe to export as a top-level object.
//
// The auth mode (current-realm vs previous-realm) is decided at construction time:
//   - New() and NewWithAddress() use current-realm auth.
//   - NewWithOrigin() and NewWithAddressByPrevious() use previous-realm auth.
//
// All ownership operations (TransferOwnership, DropOwnership, Owned, AssertOwned)
// automatically use the configured auth mode.
type Ownable struct {
	owner    address
	previous bool // if true, ownership is checked against the previous realm
}

// New creates an Ownable owned by the current realm, using current-realm auth.
func New() *Ownable {
	return &Ownable{
		owner: runtime.CurrentRealm().Address(),
	}
}

// NewWithOrigin creates an Ownable owned by the origin caller (the user who
// initiated the transaction). Must be called from init() where
// PreviousRealm() is the origin caller. Uses previous-realm auth.
func NewWithOrigin() *Ownable {
	origin := runtime.OriginCaller()
	previous := runtime.PreviousRealm()
	if origin != previous.Address() {
		panic("NewWithOrigin() should be called from init() where std.PreviousRealm() is origin")
	}
	return &Ownable{
		owner:    origin,
		previous: true,
	}
}

// NewWithAddress creates an Ownable with the given address as owner,
// using current-realm auth.
func NewWithAddress(addr address) *Ownable {
	return &Ownable{
		owner: addr,
	}
}

// NewWithAddressByPrevious creates an Ownable with the given address as owner,
// using previous-realm auth.
func NewWithAddressByPrevious(addr address) *Ownable {
	return &Ownable{
		owner:    addr,
		previous: true,
	}
}

// Owned returns true if the caller is the owner, according to the configured auth mode.
func (o *Ownable) Owned() bool {
	if o == nil {
		return false
	}
	if o.previous {
		return runtime.PreviousRealm().Address() == o.owner
	}
	return runtime.CurrentRealm().Address() == o.owner
}

// AssertOwned panics if the caller is not the owner, according to the configured auth mode.
func (o *Ownable) AssertOwned() {
	if !o.Owned() {
		panic(ErrUnauthorized)
	}
}

// TransferOwnership transfers ownership of the Ownable to a new address.
// Uses the configured auth mode to verify the caller.
func (o *Ownable) TransferOwnership(newOwner address) error {
	if !o.Owned() {
		return ErrUnauthorized
	}

	if !newOwner.IsValid() {
		return ErrInvalidAddress
	}

	prevOwner := o.owner
	o.owner = newOwner
	chain.Emit(
		OwnershipTransferEvent,
		"from", prevOwner.String(),
		"to", newOwner.String(),
	)

	return nil
}

// DropOwnership removes the owner, effectively disabling any owner-related actions.
// Uses the configured auth mode to verify the caller.
func (o *Ownable) DropOwnership() error {
	if !o.Owned() {
		return ErrUnauthorized
	}
	prevOwner := o.owner
	o.owner = ""
	chain.Emit(
		OwnershipTransferEvent,
		"from", prevOwner.String(),
		"to", "",
	)
	return nil
}

// Owner returns the owner address from Ownable.
func (o *Ownable) Owner() address {
	if o == nil {
		return address("")
	}
	return o.owner
}

// Package authorizable is an extension of p/nt/ownable;
// It allows the user to instantiate an Authorizable struct, which extends
// p/nt/ownable with a list of users that are authorized for something.
// By using authorizable, you have a superuser (ownable), as well as another
// authorization level, which can be used for adding moderators or similar to your realm.
package authorizable

import (
	"chain/runtime"

	"gno.land/p/nt/avl/v0"
	"gno.land/p/nt/ownable/v0"
	"gno.land/p/nt/ufmt/v0"
)

type Authorizable struct {
	*ownable.Ownable           // owner in ownable is superuser
	authorized       *avl.Tree // chain.Addr > struct{}{}
}

// New creates an Authorizable from an existing *ownable.Ownable.
// The owner is automatically added to the auth list.
// The auth mode (current-realm vs previous-realm) is inherited from the
// provided Ownable. Use the ownable constructors to choose the mode:
//
//	// Current-realm auth (caller is the realm making the call):
//	authorizable.New(ownable.New())
//
//	// Previous-realm auth (caller is the user/realm one step back):
//	authorizable.New(ownable.NewWithOrigin())
//
//	// Explicit address, current-realm auth:
//	authorizable.New(ownable.NewWithAddress(addr))
//
//	// Explicit address, previous-realm auth:
//	authorizable.New(ownable.NewWithAddressByPrevious(addr))
func New(o *ownable.Ownable) *Authorizable {
	a := &Authorizable{
		Ownable:    o,
		authorized: avl.NewTree(),
	}

	// Add owner to auth list
	a.authorized.Set(a.Owner().String(), struct{}{})
	return a
}

func (a *Authorizable) AddToAuthList(addr address) error {
	if !a.Owned() {
		return ErrNotSuperuser
	}
	return a.addToAuthList(addr)
}

func (a *Authorizable) addToAuthList(addr address) error {
	if _, exists := a.authorized.Get(addr.String()); exists {
		return ErrAlreadyInList
	}

	a.authorized.Set(addr.String(), struct{}{})

	return nil
}

func (a *Authorizable) DeleteFromAuthList(addr address) error {
	if !a.Owned() {
		return ErrNotSuperuser
	}
	return a.deleteFromAuthList(addr)
}

func (a *Authorizable) deleteFromAuthList(addr address) error {
	if !a.authorized.Has(addr.String()) {
		return ErrNotInAuthList
	}

	if _, removed := a.authorized.Remove(addr.String()); !removed {
		str := ufmt.Sprintf("authorizable: could not remove %s from auth list", addr.String())
		panic(str)
	}

	return nil
}

func (a *Authorizable) OnAuthList() error {
	current := runtime.CurrentRealm().Address()
	return a.onAuthList(current)
}

func (a *Authorizable) PreviousOnAuthList() error {
	previous := runtime.PreviousRealm().Address()
	return a.onAuthList(previous)
}

func (a *Authorizable) onAuthList(caller address) error {
	if !a.authorized.Has(caller.String()) {
		return ErrNotInAuthList
	}
	return nil
}

func (a Authorizable) AssertOnAuthList() {
	err := a.OnAuthList()
	if err != nil {
		panic(err)
	}
}

func (a Authorizable) AssertPreviousOnAuthList() {
	err := a.PreviousOnAuthList()
	if err != nil {
		panic(err)
	}
}

