package md

import (
	"strings"

	"gno.land/p/nt/ufmt/v0"
)

// Builder helps to build a Markdown string from individual elements
type Builder struct {
	elements []string
}

// NewBuilder creates a new Builder instance
func NewBuilder() *Builder {
	return &Builder{}
}

// Add adds a Markdown element to the builder
func (m *Builder) Add(md ...string) *Builder {
	m.elements = append(m.elements, md...)
	return m
}

// Render returns the final Markdown string joined with the specified separator
func (m *Builder) Render(separator string) string {
	return strings.Join(m.elements, separator)
}

// Bold returns bold text for markdown
func Bold(text string) string {
	return ufmt.Sprintf("**%s**", text)
}

// Italic returns italicized text for markdown
func Italic(text string) string {
	return ufmt.Sprintf("*%s*", text)
}

// Strikethrough returns strikethrough text for markdown
func Strikethrough(text string) string {
	return ufmt.Sprintf("~~%s~~", text)
}

// H1 returns a level 1 header for markdown
func H1(text string) string {
	return ufmt.Sprintf("# %s\n", text)
}

// H2 returns a level 2 header for markdown
func H2(text string) string {
	return ufmt.Sprintf("## %s\n", text)
}

// H3 returns a level 3 header for markdown
func H3(text string) string {
	return ufmt.Sprintf("### %s\n", text)
}

// H4 returns a level 4 header for markdown
func H4(text string) string {
	return ufmt.Sprintf("#### %s\n", text)
}

// H5 returns a level 5 header for markdown
func H5(text string) string {
	return ufmt.Sprintf("##### %s\n", text)
}

// H6 returns a level 6 header for markdown
func H6(text string) string {
	return ufmt.Sprintf("###### %s\n", text)
}

// BulletList returns an bullet list for markdown
func BulletList(items []string) string {
	var sb strings.Builder
	for _, item := range items {
		sb.WriteString(ufmt.Sprintf("- %s\n", item))
	}
	return sb.String()
}

// OrderedList returns an ordered list for markdown
func OrderedList(items []string) string {
	var sb strings.Builder
	for i, item := range items {
		sb.WriteString(ufmt.Sprintf("%d. %s\n", i+1, item))
	}
	return sb.String()
}

// TodoList returns a list of todo items with checkboxes for markdown
func TodoList(items []string, done []bool) string {
	var sb strings.Builder

	for i, item := range items {
		checkbox := " "
		if done[i] {
			checkbox = "x"
		}
		sb.WriteString(ufmt.Sprintf("- [%s] %s\n", checkbox, item))
	}
	return sb.String()
}

// Blockquote returns a blockquote for markdown
func Blockquote(text string) string {
	lines := strings.Split(text, "\n")
	var sb strings.Builder
	for _, line := range lines {
		sb.WriteString(ufmt.Sprintf("> %s\n", line))
	}

	return sb.String()
}

// InlineCode returns inline code for markdown
func InlineCode(code string) string {
	return ufmt.Sprintf("`%s`", code)
}

// CodeBlock creates a markdown code block
func CodeBlock(content string) string {
	return ufmt.Sprintf("```\n%s\n```", content)
}

// LanguageCodeBlock creates a markdown code block with language-specific syntax highlighting
func LanguageCodeBlock(language, content string) string {
	return ufmt.Sprintf("```%s\n%s\n```", language, content)
}

// LineBreak returns the specified number of line breaks for markdown
func LineBreak(count uint) string {
	if count > 0 {
		return strings.Repeat("\n", int(count)+1)
	}
	return ""
}

// HorizontalRule returns a horizontal rule for markdown
func HorizontalRule() string {
	return "---\n"
}

// Link returns a hyperlink for markdown
func Link(text, url string) string {
	return ufmt.Sprintf("[%s](%s)", text, url)
}

// Image returns an image for markdown
func Image(altText, url string) string {
	return ufmt.Sprintf("![%s](%s)", altText, url)
}

// Footnote returns a footnote for markdown
func Footnote(reference, text string) string {
	return ufmt.Sprintf("[%s]: %s", reference, text)
}

// Paragraph wraps the given text in a Markdown paragraph
func Paragraph(content string) string {
	return ufmt.Sprintf("%s\n", content)
}

// MdTable is an interface for table types that can be converted to Markdown format
type MdTable interface {
	String() string
}

// Table takes any MdTable implementation and returns its markdown representation
func Table(table MdTable) string {
	return table.String()
}

// EscapeMarkdown escapes special markdown characters in a string
func EscapeMarkdown(text string) string {
	return ufmt.Sprintf("``%s``", text)
}

// Package piechart provides functionality to render a pie chart as an SVG image.
// It takes a list of PieSlice objects, each representing a slice of the pie with a value,
// color, and label, and generates an SVG representation of the pie chart.
package piechart

import (
	"math"

	"gno.land/p/demo/svg"
	"gno.land/p/nt/ufmt/v0"
	"gno.land/p/sunspirit/md"
)

type PieSlice struct {
	Value float64
	Color string
	Label string
}

// Render creates an SVG pie chart from given slices (value, color and label).
// It returns an img svg markup as a string, including a markdown header if a non-empty title is provided.
func Render(slices []PieSlice, title string) string {
	// Validate input slices length
	if len(slices) == 0 {
		return "\npiechart fails: no data provided"
	}

	const (
		canvasWidth  = 500
		canvasHeight = 200
		centerX      = 100.0
		centerY      = 100.0
		radius       = 80.0
		legendX      = 210
		legendStartY = 30
		lineHeight   = 26
		squareSize   = 16
		fontSize     = 16
	)

	canvas := svg.NewCanvas(canvasWidth, canvasHeight)

	// Sum all values to compute slices proportions
	var total float64
	for _, s := range slices {
		total += s.Value
	}

	// Draw pie slices and legend in one pass
	startAngle := -math.Pi / 2
	for i, s := range slices {
		if s.Value > 0 {
			// --- PIE SLICE ---
			// Calculate angle span for current slice
			angle := (s.Value / total) * 2 * math.Pi
			endAngle := startAngle + angle

			// Compute start and end points on the circle circumference
			cosStart, sinStart := math.Cos(startAngle), math.Sin(startAngle)
			cosEnd, sinEnd := math.Cos(endAngle), math.Sin(endAngle)
			x1 := centerX + radius*cosStart
			y1 := centerY + radius*sinStart
			x2 := centerX + radius*cosEnd
			y2 := centerY + radius*sinEnd

			// Determine if the arc should be a large arc (> 180 degrees) (Arc direction)
			largeArcFlag := 0
			if angle > math.Pi {
				largeArcFlag = 1
			}

			// Build the SVG path for the pie slice
			path := ufmt.Sprintf(
				"M%.2f,%.2f L%.2f,%.2f A%.2f,%.2f 0 %d 1 %.2f,%.2f Z",
				centerX, centerY, x1, y1, radius, radius, largeArcFlag, x2, y2,
			)

			// Colored slice
			canvas.Append(svg.Path{
				D:    path,
				Fill: s.Color,
			})

			startAngle = endAngle
		}

		// --- LEGEND ---
		y := legendStartY + i*lineHeight
		// Colored square representing slice color
		canvas.Append(svg.Rectangle{
			X:      legendX,
			Y:      y - squareSize/2,
			Width:  squareSize,
			Height: squareSize,
			Fill:   s.Color,
		})

		// Legend text showing label, value and percentage
		text := ufmt.Sprintf("%s: %.0f (%.1f%%)", s.Label, s.Value, s.Value*100/total)
		canvas.Append(svg.Text{
			X:    legendX + squareSize + 8,
			Y:    y + fontSize/3,
			Text: text,
			Fill: "#54595D",
			Attr: svg.BaseAttrs{
				Style: ufmt.Sprintf("font-family:'Inter var',sans-serif;font-size:%dpx;", fontSize),
			},
		})
	}

	if title == "" {
		return canvas.Render("Pie Chart")
	}
	return md.H2(title) + canvas.Render("Pie Chart "+title)
}

package tablesort

import (
	"net/url"
	"strings"

	"gno.land/p/mason/md"
	"gno.land/p/nt/ufmt/v0"
)

// Table holds the headings and rows for rendering.
// Each row must have the same number of cells as there are headings.
type Table struct {
	Headings []string   // ["A", "B", "C"]
	Rows     [][]string // [["a1","b1","c1"], ["a2","b2","c2"], ...]
}

// Render generates a Markdown table from a Table struct with sortable columns based on URL params.
// paramPrefix is an optional prefix for in the URL to identify the tablesort Renders (e.g. "members-").
func Render(u *url.URL, table *Table, paramPrefix string) string {
	direction := ""
	currentHeading := ""
	if h := u.Query().Get(paramPrefix + "sort-asc"); h != "" {
		direction = "asc"
		currentHeading = h
	} else if h := u.Query().Get(paramPrefix + "sort-desc"); h != "" {
		direction = "desc"
		currentHeading = h
	}

	var sb strings.Builder

	// Find the index of the column to sort
	colIndex := -1
	for i, h := range table.Headings {
		if h == currentHeading {
			colIndex = i
			break
		}
	}

	// Sort rows if necessary
	if colIndex != -1 {
		SortRows(table.Rows, colIndex, direction == "asc")
	}

	// Build header
	sb.WriteString(buildHeader(u, table.Headings, currentHeading, direction, paramPrefix))
	sb.WriteString("\n")

	numCols := len(table.Headings)

	// Build rows
	for i, row := range table.Rows {
		// Validate row length
		if len(row) != numCols {
			return "tablesort fails: row " + ufmt.Sprintf("%d", i+1) + " has " +
				ufmt.Sprintf("%d", len(row)) + " cells, expected " +
				ufmt.Sprintf("%d", numCols) + ", because there are " + ufmt.Sprintf("%d", numCols) + " columns.\n"
		}

		sb.WriteString("|")
		for _, cell := range row {
			sb.WriteString(" " + cell + " |")
		}
		sb.WriteString("\n")
	}

	return sb.String()
}

// buildHeader builds the Markdown header row with clickable links and arrows
func buildHeader(u *url.URL, headings []string, currentHeading, direction string, paramPrefix string) string {
	var sb strings.Builder
	sb.WriteString("|")
	for _, h := range headings {
		arrow := ""
		if h == currentHeading {
			if direction == "asc" {
				arrow = " ↑"
			} else if direction == "desc" {
				arrow = " ↓"
			}
		}

		// Build URL for the header link with toggle logic
		newURL := *u
		q := newURL.Query()
		if h == currentHeading {
			// Toggle sort direction
			if direction == "asc" {
				q.Del(paramPrefix + "sort-asc")
				q.Set(paramPrefix+"sort-desc", h)
			} else {
				q.Del(paramPrefix + "sort-desc")
				q.Set(paramPrefix+"sort-asc", h)
			}
		} else {
			// First click defaults to descending
			q.Del(paramPrefix + "sort-asc")
			q.Set(paramPrefix+"sort-desc", h)
		}
		newURL.RawQuery = q.Encode()
		link := md.Link(h+arrow, newURL.String())
		sb.WriteString(" " + link + " |")
	}

	sb.WriteString("\n|")
	for range headings {
		sb.WriteString(" --- |")
	}
	return sb.String()
}

// Package tablesort provides functionality to render a Markdown table with sortable columns.
// It allows users to click on column headers to sort the table in ascending or descending sort direction.
// The sorting state is managed via URL query parameters.
// It displays an error if the table is malformed (e.g. rows with missing cells).
// Multiple tablesort can be rendered on the same page by using a paramPrefix for each Render (See the Render function).
package tablesort

import (
	"sort"
)

// rowSorter implements sort.Interface for sorting rows by a specific column.
type rowSorter struct {
	rows      [][]string
	colIndex  int
	ascending bool
}

func (rs rowSorter) Len() int {
	return len(rs.rows)
}

func (rs rowSorter) Less(i, j int) bool {
	iCell := rs.rows[i][rs.colIndex]
	jCell := rs.rows[j][rs.colIndex]
	if rs.ascending {
		return iCell < jCell
	}
	return iCell > jCell
}

func (rs rowSorter) Swap(i, j int) {
	rs.rows[i], rs.rows[j] = rs.rows[j], rs.rows[i]
}

// SortRows sorts the rows slice by a given column index and direction
func SortRows(rows [][]string, colIndex int, ascending bool) {
	sort.Sort(rowSorter{rows, colIndex, ascending})
}

// Package urlfilter provides functionality to filter items based on URL query parameters.
// It is designed to work with an avl.Tree structure where each key represents a filter
// and each value is an avl.Tree containing items associated with that filter.
package urlfilter

import (
	"net/url"
	"strings"

	"gno.land/p/nt/avl/v0"
	"gno.land/p/nt/ufmt/v0"
	"gno.land/p/sunspirit/md"
)

// ApplyFilters filters items based on the "filter" query parameter in the given URL
// and generates a Markdown representation of all available filters.
//
// Expected `items` structure:
//   - `items` is an *avl.Tree where each key is a filter name (e.g., "T1", "size:XL", "on_sale")
//     and each value is an *avl.Tree containing the items for that filter.
//   - Each item tree uses:
//     Key   (string): Unique item identifier
//     Value (any)   : Optional associated item data
//
// Example:
//
//	// Build the main filters tree
//	filters := avl.NewTree()
//
//	// Subtree for filter "T1"
//	t1Items := avl.NewTree()
//	t1Items.Set("item1", nil)
//	t1Items.Set("item2", nil)
//	filters.Set("T1", t1Items)
//
//	// URL with active filter "T1"
//	u, _ := url.Parse("/shop?filter=T1")
//
//	mdFilters, items := ApplyFilters(u, filters, "filter")
//
//	// mdFilters	→ Markdown links for toggling filters
//	// items    	→ AVL tree containing the filtered items
func ApplyFilters(u *url.URL, items *avl.Tree, paramName string) (string, *avl.Tree) {
	active := parseFilterMap(u.Query(), paramName)
	allFilters := make([]string, 0)
	resultTree := avl.NewTree()

	// Iterate over each filter group in the items tree
	items.Iterate("", "", func(filterKey string, subtree interface{}) bool {
		allFilters = append(allFilters, filterKey)

		tree, ok := subtree.(*avl.Tree)
		if !ok {
			return false
		}

		// Add items to result if there are no active filters
		// or if the current filter is active
		tree.Iterate("", "", func(itemKey string, _ interface{}) bool {
			if len(active) == 0 || active[filterKey] {
				resultTree.Set(itemKey, filterKey)
			}
			return false
		})
		return false
	})

	// Build Markdown links for toggling each filter
	var sb strings.Builder
	for _, f := range allFilters {
		q := toggleFilterQuery(active, f, allFilters, paramName)
		urlStr := buildURL(u.Path, q)
		sb.WriteString(ufmt.Sprintf(" | %v ", md.Link(formatLabel(f, active[f]), urlStr)))
	}

	return sb.String(), resultTree
}

// buildURL returns a path + query string, omitting the "?" if no query exists.
func buildURL(path string, query url.Values) string {
	if enc := query.Encode(); enc != "" {
		return path + "?" + enc
	}
	return path
}

// parseFilterMap reads the "filter" query parameter and converts it into a map
// where keys are filter names and values are true for active filters.
//
// Example:
//
//	"filter=T1,T2" -> map[string]bool{"T1": true, "T2": true}
func parseFilterMap(query url.Values, paramName string) map[string]bool {
	filterStr := strings.TrimSpace(query.Get(paramName))
	if filterStr == "" {
		return map[string]bool{}
	}
	m := make(map[string]bool)
	for _, f := range strings.Split(filterStr, ",") {
		if f = strings.TrimSpace(f); f != "" {
			m[f] = true
		}
	}
	return m
}

// toggleFilterQuery returns a new query string with the given filter toggled.
// - If the filter is currently active, it will be removed.
// - If it is inactive, it will be added.
// The order of filters follows the `all` list for consistency.
func toggleFilterQuery(active map[string]bool, toggled string, all []string, paramName string) url.Values {
	newFilters := []string{}
	for _, f := range all {
		if f == toggled {
			if !active[f] { // Add if it was inactive
				newFilters = append(newFilters, f)
			}
		} else if active[f] { // Keep other active filters
			newFilters = append(newFilters, f)
		}
	}
	q := url.Values{}
	if len(newFilters) > 0 {
		q.Set(paramName, strings.Join(newFilters, ","))
	}
	return q
}

// formatLabel returns the Markdown-formatted label for a filter,
// showing active filters in bold (**filter**) and inactive filters
// with strikethrough (~~filter~~).
func formatLabel(name string, active bool) string {
	if active {
		return md.Bold(name)
	}
	return md.Strikethrough(name)
}

package grc20reg

import (
	"chain"
	"chain/runtime"

	"gno.land/p/demo/tokens/grc20"
	"gno.land/p/nt/avl/v0"
	"gno.land/p/nt/avl/v0/rotree"
	"gno.land/p/nt/fqname/v0"
	"gno.land/p/nt/ufmt/v0"
)

var registry = avl.NewTree() // rlmPath[.slug] -> *Token (slug is optional)
func Register(cur realm, token *grc20.Token, slug string) {
	rlmPath := runtime.PreviousRealm().PkgPath()
	key := fqname.Construct(rlmPath, slug)
	registry.Set(key, token)
	chain.Emit(
		registerEvent,
		"pkgpath", rlmPath,
		"slug", slug,
	)
}

func Get(key string) *grc20.Token {
	token, ok := registry.Get(key)
	if !ok {
		return nil
	}
	return token.(*grc20.Token)
}

func MustGet(key string) *grc20.Token {
	token := Get(key)
	if token == nil {
		panic("unknown token: " + key)
	}
	return token
}

func Render(path string) string {
	switch {
	case path == "": // home
		// TODO: add pagination
		s := ""
		count := 0
		registry.Iterate("", "", func(key string, tokenI any) bool {
			count++
			token := tokenI.(*grc20.Token)
			rlmPath, slug := fqname.Parse(key)
			rlmLink := fqname.RenderLink(rlmPath, slug)
			infoLink := "/r/demo/grc20reg:" + key
			s += ufmt.Sprintf("- **%s** - %s - [info](%s)\n", token.GetName(), rlmLink, infoLink)
			return false
		})
		if count == 0 {
			return "No registered token."
		}
		return s
	default: // specific token
		key := path
		token := MustGet(key)
		rlmPath, slug := fqname.Parse(key)
		rlmLink := fqname.RenderLink(rlmPath, slug)
		s := ufmt.Sprintf("# %s\n", token.GetName())
		s += ufmt.Sprintf("- symbol: **%s**\n", token.GetSymbol())
		s += ufmt.Sprintf("- realm: %s\n", rlmLink)
		s += ufmt.Sprintf("- decimals: %d\n", token.GetDecimals())
		s += ufmt.Sprintf("- total supply: %d\n", token.TotalSupply())
		return s
	}
}

const registerEvent = "register"

func GetRegistry() *rotree.ReadOnlyTree {
	return rotree.Wrap(registry, nil)
}

package dao

import (
	"chain"
	"chain/runtime"
	"errors"
	"strconv"

	"gno.land/p/nt/ufmt/v0"
)

// dao is the actual govDAO implementation, having all the needed business logic
var dao DAO

// allowedDAOs contains realms that can be used to update the actual govDAO implementation,
// and validate Proposals.
// This is like that to be able to rollback using a previous govDAO implementation in case
// the latest implementation has a breaking bug. After a test period, a proposal can be
// executed to remove all previous govDAOs implementations and leave the last one.
var allowedDAOs []string

// proposals contains all the proposals in history.
var proposals *Proposals = NewProposals()

// Remember this realm for rendering.
var gRealm = runtime.CurrentRealm()

// Render calls directly to Render's DAO implementation.
// This allows to have this realm as the main entry point for everything.
func Render(p string) string {
	if dao == nil {
		return "DAO not initialized"
	}
	return dao.Render(gRealm.PkgPath(), p)
}

// MustCreateProposal is an utility method that does the same as CreateProposal,
// but instead of erroing if something happens, it panics.
func MustCreateProposal(cur realm, r ProposalRequest) ProposalID {
	pid, err := CreateProposal(cur, r)
	if err != nil {
		panic(err.Error())
	}

	return pid
}

// ExecuteProposal will try to execute the proposal with the provided ProposalID.
// If the proposal was denied, it will return false. If the proposal is correctly
// executed, it will return true. If something happens this function will panic.
func ExecuteProposal(cur realm, pid ProposalID) bool {
	if dao == nil {
		return false
	}
	execute, err := dao.PreExecuteProposal(pid)
	if err != nil {
		panic(err.Error())
	}

	if !execute {
		return false
	}
	prop, err := GetProposal(cur, pid)
	if err != nil {
		panic(err.Error())
	}
	if err := prop.executor.Execute(cross); err != nil {
		panic(err.Error())
	}
	return true
}

// CreateProposal will try to create a new proposal, that will be validated by the actual
// govDAO implementation. If the proposal cannot be created, an error will be returned.
func CreateProposal(cur realm, r ProposalRequest) (ProposalID, error) {
	if dao == nil {
		return -1, errors.New("DAO not initialized")
	}
	author, err := dao.PreCreateProposal(r)
	if err != nil {
		return -1, err
	}

	p := &Proposal{
		author:      author,
		title:       r.title,
		description: r.description,
		executor:    r.executor,
		allowedDAOs: allowedDAOs[:],
	}

	pid := proposals.SetProposal(p)
	dao.PostCreateProposal(r, pid)

	chain.Emit("ProposalCreated",
		"id", strconv.FormatInt(int64(pid), 10),
	)

	return pid, nil
}

func MustVoteOnProposal(cur realm, r VoteRequest) {
	if err := VoteOnProposal(cur, r); err != nil {
		panic(err.Error())
	}
}

// VoteOnProposal sends a vote to the actual govDAO implementation.
// If the voter cannot vote the specified proposal, this method will return an error
// with the explanation of why.
func VoteOnProposal(cur realm, r VoteRequest) error {
	if dao == nil {
		return errors.New("DAO not initialized")
	}
	return dao.VoteOnProposal(r)
}

// MustVoteOnProposalSimple is like MustVoteOnProposal but intended to be used through gnokey with basic types.
func MustVoteOnProposalSimple(cur realm, pid int64, option string) {
	MustVoteOnProposal(cur, VoteRequest{
		Option:     VoteOption(option),
		ProposalID: ProposalID(pid),
	})
}

func MustGetProposal(cur realm, pid ProposalID) *Proposal {
	p, err := GetProposal(cur, pid)
	if err != nil {
		panic(err.Error())
	}

	return p
}

// GetProposal gets created proposal by its ID
func GetProposal(cur realm, pid ProposalID) (*Proposal, error) {
	if dao == nil {
		return nil, errors.New("DAO not initialized")
	}
	if err := dao.PreGetProposal(pid); err != nil {
		return nil, err
	}

	prop := proposals.GetProposal(pid)
	if prop == nil {
		return nil, errors.New(ufmt.Sprintf("Proposal %v does not exist.", int64(pid)))
	}

	if err := dao.PostGetProposal(pid, prop); err != nil {
		return nil, err
	}

	return prop, nil
}

// UpdateImpl is a method intended to be used on a proposal.
// This method will update the current govDAO implementation
// to a new one. AllowedDAOs are a list of realms that can
// call this method, in case the new DAO implementation had
// a breaking bug. Any value set as nil will be ignored.
// If AllowedDAOs field is not set correctly, the actual DAO
// implementation wont be able to execute new Proposals!
func UpdateImpl(cur realm, r UpdateRequest) {
	gRealm := runtime.PreviousRealm().PkgPath()

	if !InAllowedDAOs(gRealm) {
		panic("permission denied for prev realm: " + gRealm)
	}

	if r.AllowedDAOs != nil {
		allowedDAOs = r.AllowedDAOs
	}

	if r.DAO != nil {
		dao = r.DAO
	}
}

func AllowedDAOs() []string {
	dup := make([]string, len(allowedDAOs))
	copy(dup, allowedDAOs)
	return dup
}

func InAllowedDAOs(pkg string) bool {
	if len(allowedDAOs) == 0 {
		return true // corner case for initialization
	}
	for _, d := range allowedDAOs {
		if pkg == d {
			return true
		}
	}
	return false
}

package dao

import (
	"chain/runtime"
	"errors"

	"gno.land/p/nt/avl/v0"
	"gno.land/p/nt/seqid/v0"
)

type ProposalID int64

func (pid ProposalID) String() string {
	return seqid.ID(pid).String()
}

// VoteOption is the limited voting option for a DAO proposal
// New govDAOs can create their own VoteOptions if needed in the
// future.
type VoteOption string

const (
	AbstainVote VoteOption = "ABSTAIN" // Side is not chosen
	YesVote     VoteOption = "YES"     // Proposal should be accepted
	NoVote      VoteOption = "NO"      // Proposal should be rejected
)

type VoteRequest struct {
	Option     VoteOption
	ProposalID ProposalID
	Metadata   interface{}
}

func NewProposalRequest(title string, description string, executor Executor) ProposalRequest {
	return ProposalRequest{
		title:       title,
		description: description,
		executor:    executor,
	}
}

func NewProposalRequestWithFilter(title string, description string, executor Executor, filter Filter) ProposalRequest {
	return ProposalRequest{
		title:       title,
		description: description,
		executor:    executor,
		filter:      filter,
	}
}

type Filter interface{}

type ProposalRequest struct {
	title       string
	description string
	executor    Executor
	filter      Filter
}

func (p *ProposalRequest) Title() string {
	return p.title
}

func (p *ProposalRequest) Description() string {
	return p.description
}

func (p *ProposalRequest) Filter() Filter {
	return p.filter
}

type Proposal struct {
	author address

	title       string
	description string

	executor    Executor
	allowedDAOs []string
}

func (p *Proposal) Author() address {
	return p.author
}

func (p *Proposal) Title() string {
	return p.title
}

func (p *Proposal) Description() string {
	return p.description
}

func (p *Proposal) ExecutorString() string {
	if p.executor != nil {
		return p.executor.String()
	}

	return ""
}

func (p *Proposal) ExecutorCreationRealm() string {
	if p.executor != nil {
		return p.executor.CreationRealm()
	}

	return ""
}

func (p *Proposal) AllowedDAOs() []string {
	return append([]string(nil), p.allowedDAOs...)
}

type Proposals struct {
	seq       seqid.ID
	*avl.Tree // *avl.Tree[ProposalID]*Proposal
}

func NewProposals() *Proposals {
	return &Proposals{Tree: avl.NewTree()}
}

func (ps *Proposals) SetProposal(p *Proposal) ProposalID {
	pid := ProposalID(int64(ps.seq))
	updated := ps.Set(pid.String(), p)
	if updated {
		panic("fatal error: Override proposals is not allowed")
	}
	ps.seq = ps.seq.Next()
	return pid
}

func (ps *Proposals) GetProposal(pid ProposalID) *Proposal {
	pv, ok := ps.Get(pid.String())
	if !ok {
		return nil
	}

	return pv.(*Proposal)
}

type Executor interface {
	Execute(cur realm) error
	String() string
	CreationRealm() string
}

func NewSimpleExecutor(callback func(realm) error, description string) *SimpleExecutor {
	if callback == nil {
		panic("executor callback must not be nil")
	}

	return &SimpleExecutor{
		callback:      callback,
		desc:          description,
		creationRealm: runtime.CurrentRealm().PkgPath(),
	}
}

// SimpleExecutor implements the Executor interface using
// a callback function and a description string.
type SimpleExecutor struct {
	callback      func(realm) error
	desc          string
	creationRealm string
}

func (e *SimpleExecutor) Execute(cur realm) error {
	// Check if executor was created using the constructor func
	if e.callback == nil {
		return nil
	}

	return e.callback(cross)
}

func (e *SimpleExecutor) String() string {
	return e.desc
}

func (e *SimpleExecutor) CreationRealm() string {
	return e.creationRealm
}

func NewSafeExecutor(e Executor) *SafeExecutor {
	return &SafeExecutor{
		e: e,
	}
}

// SafeExecutor wraps an Executor to only allow its execution
// by allowed govDAOs.
type SafeExecutor struct {
	e Executor
}

func (e *SafeExecutor) Execute(cur realm) error {
	// Verify the caller is an adequate Realm
	if !InAllowedDAOs(runtime.PreviousRealm().PkgPath()) {
		return errors.New("execution only allowed by validated govDAOs")
	}

	return e.e.Execute(cross)
}

func (e *SafeExecutor) String() string {
	return e.e.String()
}

func (e *SafeExecutor) CreationRealm() string {
	return e.e.CreationRealm()
}

type DAO interface {
	// PreCreateProposal is called just before creating a new Proposal
	// It is intended to be used to get the address of the proposal, that
	// may vary depending on the DAO implementation, and to validate that
	// the requester is allowed to do a proposal
	PreCreateProposal(r ProposalRequest) (address, error)

	// PostCreateProposal is called after creating the Proposal. It is
	// intended to be used as a way to store a new proposal status, that
	// depends on the actuall govDAO implementation
	PostCreateProposal(r ProposalRequest, pid ProposalID)

	// VoteOnProposal will send a petition to vote for a specific proposal
	// to the actual govDAO implementation
	VoteOnProposal(r VoteRequest) error

	// PreGetProposal is called when someone is trying to get a proposal by ID.
	// Is intended to be used to validate who can query proposals, just in case
	// the actual govDAO implementation wants to limit the access.
	PreGetProposal(pid ProposalID) error

	// PostGetProposal is called after the proposal has been obtained. Intended to be
	// used by govDAO implementations if they need to check Proposal data to know if
	// the caller is allowed to get that kind of Proposal or not.
	PostGetProposal(pid ProposalID, p *Proposal) error

	// PreExecuteProposal is called when someone is trying to execute a proposal by ID.
	// Is intended to be used to validate who can trigger the proposal execution.
	PreExecuteProposal(pid ProposalID) (bool, error)

	// Render will return a human-readable string in markdown format that
	// will be used to show new data through the dao proxy entrypoint.
	Render(pkgpath string, path string) string
}

type UpdateRequest struct {
	DAO         DAO
	AllowedDAOs []string
}

