			),
		)
	} else {
		res.Write(
			md.Paragraph(
				// Intentionally hide flagged thread title
				ufmt.Sprintf("Moderation flags for %s", md.Link("thread", makeThreadURI(thread))),
			),
		)
	}
	res.Write(table.String())
}

