package cla

import (
	"chain"

	"gno.land/p/moul/addrset"
	"gno.land/p/moul/helplink"
	"gno.land/r/gov/dao"
)

const RequiredHashChangedEvent = "CLARequiredHashChanged"

// ProposeNewCLA creates a govdao proposal to update the CLA document hash and URL.
// When executed, it resets all existing signatures.
// Propose an empty hash to disable CLA enforcement.
func ProposeNewCLA(newHash, newURL string) dao.ProposalRequest {
	cb := func(cur realm) error {
		setRequiredHash(newHash)
		claURL = newURL
		return nil
	}

	desc := "Propose updating the CLA requirement.\n\n"
	if requiredHash != "" {
		desc += "Current hash: " + requiredHash + "\n"
	}
	if claURL != "" {
		desc += "Current URL: " + claURL + "\n"
	}
	if newHash != "" {
		desc += "New hash: " + newHash + "\n"
	}
	if newURL != "" {
		desc += "New URL: " + newURL + "\n"
	}
	if newHash == "" {
		desc += "This proposal disables CLA enforcement.\n"
	}

	return dao.NewProposalRequest(
		"Update CLA requirement",
		desc,
		dao.NewSimpleExecutor(cb, helplink.Realm("gno.land/r/sys/cla").Home()),
	)
}

func setRequiredHash(newHash string) {
	prevHash := requiredHash
	requiredHash = newHash
	signatures = addrset.Set{} // reset all signatures

	chain.Emit(
		RequiredHashChangedEvent,
		"from", prevHash,
		"to", newHash,
	)
}

package cla

import (
	"chain"
	"chain/runtime"

	"gno.land/p/moul/addrset"
)

const SignedEvent = "CLASigned"

var (
	requiredHash string // SHA256 hash of the CLA document; empty = enforcement disabled
	claURL       string // URL where the CLA document can be found
	signatures   addrset.Set
)

// Sign records a CLA signature for the caller.
// The hash must match the current required hash.
func Sign(cur realm, hash string) {
	if hash != requiredHash {
		panic("hash does not match required CLA hash")
	}

	caller := runtime.PreviousRealm().Address()
	signatures.Add(caller)

	chain.Emit(
		SignedEvent,
		"signer", caller.String(),
		"hash", hash,
	)
}

// HasValidSignature checks if an address has signed the current required CLA.
// Returns true if CLA enforcement is disabled (requiredHash == ""),
// or if the address has signed.
func HasValidSignature(addr address) bool {
	if requiredHash == "" {
		return true
	}
	return signatures.Has(addr)
}

package cla

import "gno.land/p/moul/helplink"

func Render(path string) string {
	if requiredHash == "" {
		return "# Gno CLA Registry\n\n**Status:** CLA enforcement is DISABLED\n"
	}

	output := "# Gno CLA Registry\n\n**Status:** CLA enforcement is ENABLED\n\n"
	output += "**Required Hash:** " + requiredHash + "\n"
	if claURL != "" {
		output += "**CLA Document:** " + claURL + "\n"
	}
	output += "\n### Actions\n\n"
	output += helplink.Func("Sign CLA", "Sign", "hash", requiredHash) + "\n"
	return output
}

